#!/usr/bin/env python3
"""Write UTF-8 sidecar Hebrew strings for long entries."""
from pathlib import Path

OUT = Path(__file__).resolve().parent / "he_fix_sidecar"
OUT.mkdir(exist_ok=True)


def w(name, text):
    (OUT / name).write_text(text, encoding="utf-8")


